export async function singleFlight(
  key: string,
  task: () => Promise<string>,
): Promise<string> {
  const entry = pending.get(key);
  if (entry) {
    if (entry.error) throw entry.error;
    return entry.promise;
  }
  try {
    const operation = task();
    pending.set(key, { promise: operation });
    return await operation;
  } catch (error) {
    pending.set(key, { error });
    throw error;
  }
}

export function resetFlights(): void {
